input.newString:
export function formatTitle(value, mode = 'plain') {
  if (mode === 'upper') return value.toUpperCase()
  if (mode === 'lower') return value.toLowerCase()
  if (mode === 'title') return value.split(/(\s+)/).map((part, idx, arr) => idx % 2 === 0 ? part.charAt(0).toUpperCase() + part.slice(1).toLowerCase() : part).join('')
  return value
}

